import{_ as d,C as a,o as l,c as h,a3 as o,E as n,w as s,j as e,a as t}from"./chunks/framework.COIRw5e5.js";const g="/versions/v0.11.0/screens/perform/macro_rows_device.png",k=JSON.parse('{"title":"Device parameter macro rows","description":"","frontmatter":{},"headers":[],"relativePath":"perform/macro-rows/device-parameter.md","filePath":"perform/macro-rows/device-parameter.md"}'),m={name:"perform/macro-rows/device-parameter.md"};function p(v,r,u,f,w,_){const i=a("ScreenHighlight"),c=a("ManualRelated");return l(),h("div",null,[r[2]||(r[2]=o('<h1 id="device-parameter-macro-rows" tabindex="-1">Device parameter macro rows <a class="header-anchor" href="#device-parameter-macro-rows" aria-label="Permalink to &quot;Device parameter macro rows&quot;">​</a></h1><p>A <strong>device parameter</strong> macro turns the knob into a control for something <strong>inside your rack chain</strong> — arpeggiator gate, seed density, scale selection, and so on. The row shows <strong>which rack, which device, and which parameter</strong> you are affecting. It does <strong>not</strong> show MIDI channels or output ports because nothing is sent as a standalone MIDI message.</p><p><img src="'+g+'" alt="Device parameter macro rows on Perform" class="screen"></p><table tabindex="0"><thead><tr><th>Row</th><th>Device</th><th>Parameter</th><th>Example in screenshot</th></tr></thead><tbody><tr><td><strong>0</strong></td><td><strong>Arp</strong></td><td><strong>Gate</strong></td><td>Arpeggiator gate length (32–96% range)</td></tr><tr><td><strong>1</strong></td><td><strong>Harmony</strong></td><td><strong>1st</strong></td><td>First harmony interval</td></tr><tr><td><strong>2</strong></td><td><strong>Seed</strong></td><td><strong>Density</strong></td><td>How many seed notes fire</td></tr><tr><td><strong>3</strong></td><td><strong>Scaler</strong></td><td><strong>Scale</strong></td><td>Which scale preset is active</td></tr></tbody></table><h2 id="reading-a-device-row" tabindex="-1">Reading a device row <a class="header-anchor" href="#reading-a-device-row" aria-label="Permalink to &quot;Reading a device row&quot;">​</a></h2>',5)),n(i,{class:"screen-highlight--macro-rows",src:"/screens/perform/macro_rows_device.png",alt:"Device parameter macro rows",x:0,y:20,w:66.4,h:80,label:"Rows"},{default:s(()=>[...r[0]||(r[0]=[e("p",null,[e("strong",null,"Rack"),t(" → "),e("strong",null,"device"),t(" → "),e("strong",null,"parameter name"),t(". The "),e("strong",null,"live value"),t(" is on the far right (percentages, note names, scale names, etc.).")],-1)])]),_:1}),r[3]||(r[3]=o('<h3 id="rack-r1-r2" tabindex="-1">Rack (<code>R1</code>, <code>R2</code>, …) <a class="header-anchor" href="#rack-r1-r2" aria-label="Permalink to &quot;Rack (`R1`, `R2`, …)&quot;">​</a></h3><p>Which rack in the active project contains the target device.</p><h3 id="device" tabindex="-1">Device <a class="header-anchor" href="#device" aria-label="Permalink to &quot;Device&quot;">​</a></h3><p>Short device type name — <strong>Arp</strong>, <strong>Harmony</strong>, <strong>Seed</strong>, <strong>Scaler</strong>, and so on. Same labels as in the <a href="./../../devices/">device reference</a>.</p><h3 id="parameter" tabindex="-1">Parameter <a class="header-anchor" href="#parameter" aria-label="Permalink to &quot;Parameter&quot;">​</a></h3><p>The field on that device the knob drives — <strong>Gate</strong>, <strong>Density</strong>, <strong>Scale</strong>, <strong>Rate</strong>, etc.</p><h3 id="live-value" tabindex="-1">Live value <a class="header-anchor" href="#live-value" aria-label="Permalink to &quot;Live value&quot;">​</a></h3><p>Shown in the device’s own units: <strong>100%</strong>, <strong>Custom</strong>, <strong>0st</strong>, and so on. Min/max limits from edit mode apply here and on the matching indicator bar.</p><h2 id="elsewhere-on-screen" tabindex="-1">Elsewhere on screen <a class="header-anchor" href="#elsewhere-on-screen" aria-label="Permalink to &quot;Elsewhere on screen&quot;">​</a></h2><p>When a knob macro targets a device parameter, that parameter’s editor row can show a <strong>knob-macro badge</strong> (filled dots + knob number). To change or clear the mapping, use <strong>Perform → edit mode</strong> — not the device parameter list.</p><h2 id="configure-these-macros" tabindex="-1">Configure these macros <a class="header-anchor" href="#configure-these-macros" aria-label="Permalink to &quot;Configure these macros&quot;">​</a></h2><p><a href="./../../macros/device-parameter">Device parameter macro mode</a> — pick rack, device, and parameter in the grid.</p>',12)),n(c,null,{default:s(()=>[...r[1]||(r[1]=[e("ul",null,[e("li",null,[e("a",{href:"./"},"Macro rows overview")]),e("li",null,[e("a",{href:"./classic-midi"},"Classic MIDI rows"),t(" — Outgoing MIDI messages")]),e("li",null,[e("a",{href:"./../../devices/"},"Device reference"),t(" — Parameters per device type")]),e("li",null,[e("a",{href:"./../../concepts/mapping"},"Mapping"),t(" — One knob macro per target")])],-1)])]),_:1})])}const P=d(m,[["render",p]]);export{k as __pageData,P as default};
